namespace sv_3cfc37882fdd4df19c54585c1a3fea9b.Client.Services;

public sealed record Shipment(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> StatusUpdates);

public sealed record StatusUpdate(
    string Description,
    DateTimeOffset Timestamp);

namespace sv_3cfc37882fdd4df19c54585c1a3fea9b.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_3cfc37882fdd4df19c54585c1a3fea9b.Client.Services;

namespace sv_3cfc37882fdd4df19c54585c1a3fea9b.Services;

public sealed class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment(
            "PKG-001",
            "In Transit",
            "Chicago, IL",
            DateTimeOffset.UtcNow.AddDays(2),
            new List<StatusUpdate>
            {
                new("Package picked up", DateTimeOffset.UtcNow.AddDays(-3)),
                new("Arrived at sorting facility", DateTimeOffset.UtcNow.AddDays(-2)),
                new("Departed Chicago hub", DateTimeOffset.UtcNow.AddDays(-1)),
            }),
        ["PKG-002"] = new Shipment(
            "PKG-002",
            "Delivered",
            "Austin, TX",
            DateTimeOffset.UtcNow.AddDays(-1),
            new List<StatusUpdate>
            {
                new("Package picked up", DateTimeOffset.UtcNow.AddDays(-5)),
                new("In transit to destination", DateTimeOffset.UtcNow.AddDays(-3)),
                new("Out for delivery", DateTimeOffset.UtcNow.AddDays(-1)),
                new("Delivered — signed by recipient", DateTimeOffset.UtcNow.AddDays(-1).AddHours(4)),
            }),
        ["PKG-003"] = new Shipment(
            "PKG-003",
            "Processing",
            "Seattle, WA",
            DateTimeOffset.UtcNow.AddDays(5),
            new List<StatusUpdate>
            {
                new("Label created", DateTimeOffset.UtcNow.AddHours(-6)),
                new("Awaiting carrier pickup", DateTimeOffset.UtcNow.AddHours(-2)),
            }),
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_3cfc37882fdd4df19c54585c1a3fea9b.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Track Shipment @TrackingNumber</PageTitle>

<h1>Shipment Tracking</h1>

@if (_loading)
{
    <div class="loading-placeholder">
        <p><em>Loading shipment details for @TrackingNumber&hellip;</em></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="alert alert-warning" role="alert">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <dl>
        <dt>Tracking Number</dt>
        <dd>@_shipment.TrackingNumber</dd>

        <dt>Status</dt>
        <dd>@_shipment.Status</dd>

        <dt>Location</dt>
        <dd>@_shipment.Location</dd>

        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h2>Status Updates</h2>
    @if (_shipment.StatusUpdates.Count == 0)
    {
        <p>No status updates yet.</p>
    }
    else
    {
        <ul>
            @foreach (var update in _shipment.StatusUpdates)
            {
                <li>
                    <strong>@update.Timestamp.ToString("g")</strong> &mdash; @update.Description
                </li>
            }
        </ul>
    }
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;
    private string? _lastLoadedTrackingNumber;

    protected override async Task OnParametersSetAsync()
    {
        if (string.Equals(_lastLoadedTrackingNumber, TrackingNumber, StringComparison.OrdinalIgnoreCase))
            return;

        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();

        _lastLoadedTrackingNumber = TrackingNumber;
        _shipment = null;
        _errorMessage = null;
        _loading = true;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, _cts.Token);
        }
        catch (OperationCanceledException)
        {
            // Request was cancelled (navigation or dispose) — do nothing
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RetryAsync()
    {
        _lastLoadedTrackingNumber = null;
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

